public class PrimitivesDemo {
    public static void main(String[] args) {
        // 1. boolean (1 bit logically, 1 byte in practice)
        boolean flag = true;
        System.out.println("boolean: " + flag);

        // 2. byte (-128 to 127)
        byte b = 127;
        byte overflow = (byte)(b + 1);  // 127 + 1 = -128 (overflow wraps!)
        System.out.println("byte 127 + 1 = " + overflow);  // -128

        // 3. int overflow
        int maxInt = Integer.MAX_VALUE;  // 2,147,483,647
        System.out.println("MAX_VALUE + 1 = " + (maxInt + 1));  // -2147483648

        // 4. long (use L suffix!)
        long bigNum = 9_876_543_210L;  // needs L — too big for int
        System.out.println("long: " + bigNum);

        // 5. float vs double precision
        float f  = 0.1f + 0.2f;
        double d = 0.1  + 0.2;
        System.out.println("float  0.1+0.2 = " + f);  // 0.3 (appears ok)
        System.out.println("double 0.1+0.2 = " + d);  // 0.30000000000000004

        // 6. char (Unicode, 0-65535)
        char c = 'A';
        char next = (char)(c + 1);  // 'B'
        System.out.println("char: " + c + " next: " + next);

        // 7. Default values for fields (not local variables!)
        // int field  = 0;  boolean field = false;  reference field = null
    }
}

public class CastingDemo {
    public static void main(String[] args) {
        // WIDENING (implicit, safe — no data loss)
        byte  b  = 42;
        short s  = b;    // byte  → short  (widening, automatic)
        int   i  = s;    // short → int    (widening, automatic)
        long  l  = i;    // int   → long   (widening, automatic)
        float f  = l;    // long  → float  (widening — but may lose precision!)
        double d = f;    // float → double (widening, automatic)
        System.out.println("Widening chain: " + b + " -> " + d);

        // NARROWING (explicit cast required — potential data loss)
        double pi    = 3.14159;
        int    piInt = (int) pi;   // truncates fraction: 3 (not rounded!)
        System.out.println("(int) 3.14159 = " + piInt);  // 3

        long bigLong = 1_000_000_000_000L;
        int  small   = (int) bigLong;  // upper bits dropped!
        System.out.println("(int) 1_000_000_000_000L = " + small);  // wrong value

        // CHAR casting
        char  c  = 'A';
        int   ci = c;           // widening: 65
        char  c2 = (char) 66;   // narrowing int to char: 'B'
        System.out.println("'A' as int: " + ci + "  66 as char: " + c2);

        // TRICKY: long to float may lose precision (both 64/32 bit but different ranges)
        long precise  = 123_456_789_012_345L;
        float approx  = precise;  // widening but LOSES precision — no cast needed!
        System.out.println("long: " + precise + "  float: " + approx);  // different!
    }
}

public class AutoboxingDemo {
    public static void main(String[] args) {
        // AUTOBOXING: primitive → wrapper (implicit)
        Integer boxed = 42;  // same as: Integer.valueOf(42)
        int     unboxed = boxed;  // UNBOXING: wrapper → primitive

        // TRICKY: Integer cache for values -128 to 127
        Integer a = 127;
        Integer b = 127;
        Integer c = 128;
        Integer d = 128;

        System.out.println("127 == 127: " + (a == b));  // TRUE (cached!)
        System.out.println("128 == 128: " + (c == d));  // FALSE (new objects!)
        System.out.println("128.equals: " + c.equals(d)); // TRUE

        // UNBOXING NULL = NullPointerException!
        Integer nullInt = null;
        try {
            int x = nullInt;  // NullPointerException!
        } catch (NullPointerException e) {
            System.out.println("NPE from unboxing null!");
        }

        // AUTOBOXING IN LOOPS = PERFORMANCE TRAP
        Long sum = 0L;  // Long, not long!
        for (long i = 0; i < 100_000; i++) {
            sum += i;  // unbox sum, add i, rebox result = 100,000 allocations!
        }
        System.out.println("Sum (slow): " + sum);

        // FIX: use primitive
        long fastSum = 0L;
        for (long i = 0; i < 100_000; i++) fastSum += i;
        System.out.println("Sum (fast): " + fastSum);
    }
}

public class StringDemo {
    public static void main(String[] args) {
        // String is IMMUTABLE — every 'modification' creates a new object
        String s = "hello";
        String upper = s.toUpperCase();  // new String, s unchanged
        System.out.println(s);      // hello
        System.out.println(upper);  // HELLO

        // String Pool (Interning)
        String a = "java";          // from pool
        String b = "java";          // same pool entry
        String c = new String("java"); // forces new heap object
        String d = c.intern();         // puts c into pool (or returns existing)

        System.out.println(a == b);  // true  (same pool object)
        System.out.println(a == c);  // false (c is separate heap object)
        System.out.println(a == d);  // true  (d is the pool entry)

        // + concatenation in loops = bad (each + creates new String)
        String result = "";
        for (int i = 0; i < 5; i++) result += i;  // creates 5 intermediate Strings
        System.out.println(result);  // 01234

        // StringBuilder: mutable, single object
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < 5; i++) sb.append(i);
        System.out.println(sb);  // 01234

        // String.format vs + for complex formatting
        String formatted = String.format("Name: %s, Age: %d", "Alice", 30);
        System.out.println(formatted);
    }
}

import java.util.*;
import java.util.stream.*;

public class VarDemo {
    public static void main(String[] args) {
        // GOOD uses of var: type obvious from RHS
        var list   = new ArrayList<String>();       // obviously ArrayList<String>
        var map    = new HashMap<String, Integer>(); // obviously HashMap
        var stream = list.stream();                  // Stream<String>

        // var infers the EXACT type from RHS
        var msg = "hello";  // String (not Object, not CharSequence)

        // var with enhanced for loop
        var numbers = List.of(1, 2, 3, 4, 5);
        for (var n : numbers) {  // n inferred as Integer
            System.out.print(n + " ");
        }

        // var with try-with-resources
        // try (var reader = new BufferedReader(...)) { ... }

        // BAD uses of var (avoid)
        var x = 0;     // unclear: int? long? short? — use int x = 0
        var y = null;  // COMPILE ERROR: cannot infer type from null

        // var cannot be used for:
        // - method parameters
        // - return types
        // - class fields
        // - catch parameters (Java 9 allows this)

        // Diamond with var
        var pairs = new ArrayList<Map.Entry<String, Integer>>();  // saves typing!

        // var is NOT dynamic typing — it's compile-time type inference
        var str = "hello";
        // str = 42;  // COMPILE ERROR: str is String, cannot assign int
        System.out.println(str.toUpperCase()); // IDE knows str is String
    }
}

