problems.solutionCode:
public class Q2 {
    public static String fitInType(long value) {
        if (value >= Byte.MIN_VALUE    && value <= Byte.MAX_VALUE)    return "byte";
        if (value >= Short.MIN_VALUE   && value <= Short.MAX_VALUE)   return "short";
        if (value >= Integer.MIN_VALUE && value <= Integer.MAX_VALUE) return "int";
        return "long";
    }

    public static void main(String[] args) {
        System.out.println(fitInType(100));           // byte
        System.out.println(fitInType(200));           // short (>127)
        System.out.println(fitInType(-129));          // short (<-128)
        System.out.println(fitInType(40000));         // int
        System.out.println(fitInType(3_000_000_000L)); // long
        System.out.println(fitInType(Long.MAX_VALUE)); // long
    }
}

