problems.solutionCode:
public class Q3 {
    public static boolean doubleEquals(double a, double b, double epsilon) {
        return Math.abs(a - b) <= epsilon;
    }

    // Better version for large numbers (relative epsilon)
    public static boolean doubleEqualsRelative(double a, double b, double epsilon) {
        if (a == b) return true; // handles infinities
        return Math.abs(a - b) <= epsilon * Math.max(Math.abs(a), Math.abs(b));
    }

    public static void main(String[] args) {
        double sum = 0.1 + 0.2;
        System.out.println("0.1+0.2 == 0.3: "    + (sum == 0.3));               // false!
        System.out.println("Actual value: "        + sum);                       // 0.30000000000000004
        System.out.println("doubleEquals 1e-9: "   + doubleEquals(sum, 0.3, 1e-9));  // true
        System.out.println("doubleEquals 1e-15: "  + doubleEquals(sum, 0.3, 1e-15)); // false (too tight)

        // Large number comparison
        double x = 1_000_000.1;
        double y = 1_000_000.2;
        System.out.println("Relative: " + doubleEqualsRelative(x, y, 1e-6)); // false
    }
}

