public class Q4 {
    public static boolean[] integerCacheDemo() {
        Integer a = 127; Integer b = 127;
        Integer c = 128; Integer d = 128;
        return new boolean[]{
            a == b,        // true  — cached, same object
            c == d,        // false — not cached, different objects
            c.equals(d)    // true  — value equality always works
        };
    }

    public static void main(String[] args) {
        boolean[] r = integerCacheDemo();
        System.out.println("127 == 127: "      + r[0]); // true
        System.out.println("128 == 128: "      + r[1]); // false
        System.out.println("128.equals(128): " + r[2]); // true
        // Moral: NEVER use == to compare Integer objects
        // ALWAYS use .equals() or unbox to primitive first
    }
}

