public class Q5 {
    public static int parseInt(String s, int defaultVal) {
        if (s == null) return defaultVal;
        try { return Integer.parseInt(s.trim()); }
        catch (NumberFormatException e) { return defaultVal; }
    }

    public static double parseDouble(String s, double defaultVal) {
        if (s == null) return defaultVal;
        try { return Double.parseDouble(s.trim()); }
        catch (NumberFormatException e) { return defaultVal; }
    }

    public static boolean parseBoolean(String s) {
        if (s == null) return false;
        return switch (s.trim().toLowerCase()) {
            case "true", "yes", "1", "on"  -> true;
            case "false", "no", "0", "off" -> false;
            default -> Boolean.parseBoolean(s); // standard parse
        };
    }

    public static void main(String[] args) {
        System.out.println(parseInt("42", 0));         // 42
        System.out.println(parseInt("abc", -1));       // -1
        System.out.println(parseInt(null, 99));         // 99
        System.out.println(parseDouble("3.14", 0.0));  // 3.14
        System.out.println(parseBoolean("yes"));       // true
        System.out.println(parseBoolean("0"));          // false
        System.out.println(parseBoolean("TRUE"));       // true
    }
}

