public class Q6 {
    public static String analyzeBits(int value) {
        String binary = String.format("%32s",
            Integer.toBinaryString(value)).replace(' ', '0');
        char signBit = binary.charAt(0);
        String valueBits = binary.substring(1);

        return String.format(
            "Value: %d%n" +
            "Hex:   0x%08X%n" +
            "Octal: %o%n" +
            "Bin:   [%c] %s%n" +  // [sign] value_bits
            "       ^ sign bit (%s)",
            value,
            value,
            value,
            signBit, valueBits,
            signBit == '1' ? "negative" : "positive"
        );
    }

    public static void main(String[] args) {
        System.out.println(analyzeBits(42));
        System.out.println();
        System.out.println(analyzeBits(-1));  // all bits = 1 (two's complement)
        System.out.println();
        System.out.println(analyzeBits(Integer.MAX_VALUE)); // 0 followed by 31 ones
    }
}

