public class Q7 {
    static final int N = 10_000;

    static long timeStringConcat() {
        long start = System.nanoTime();
        String s = "";
        for (int i = 0; i < N; i++) s += "x";
        if (s.isEmpty()) System.out.println(); // prevent dead-code elimination
        return System.nanoTime() - start;
    }

    static long timeStringBuilder() {
        long start = System.nanoTime();
        StringBuilder sb = new StringBuilder(N); // pre-size to avoid resizing
        for (int i = 0; i < N; i++) sb.append("x");
        String s = sb.toString();
        if (s.isEmpty()) System.out.println(); // prevent dead-code elimination
        return System.nanoTime() - start;
    }

    public static double benchmarkRatio() {
        // Warm up JIT first
        timeStringConcat();   timeStringBuilder();
        timeStringConcat();   timeStringBuilder();

        long concat  = timeStringConcat();
        long builder = timeStringBuilder();
        return (double) concat / builder;
    }

    public static void main(String[] args) {
        double ratio = benchmarkRatio();
        System.out.printf("String+ is %.1fx slower than StringBuilder%n", ratio);
        System.out.printf("Expected: > 10x (typically 50-500x for N=10000)%n");
    }
}

