problems.solutionCode:
import java.util.*;

public class Q8 {
    public static Map<String, String> convertAll(double value) {
        Map<String, String> map = new LinkedHashMap<>();
        map.put("byte",  String.valueOf((byte)  value));
        map.put("short", String.valueOf((short) value));
        map.put("int",   String.valueOf((int)   value));  // NaN->0, +Inf->MAX_VALUE
        map.put("long",  String.valueOf((long)  value));
        map.put("float", String.valueOf((float) value));  // may lose precision
        // char only if in valid range
        if (!Double.isNaN(value) && value >= 0 && value <= 65535)
            map.put("char", String.valueOf((char) (int) value));
        else
            map.put("char", "(out of range)");
        return map;
    }

    public static void main(String[] args) {
        System.out.println("--- 65.7 ---");
        convertAll(65.7).forEach((k, v) -> System.out.println(k + " -> " + v));
        // int=65 (truncated), char='A' (65)

        System.out.println("--- NaN ---");
        convertAll(Double.NaN).forEach((k, v) -> System.out.println(k + " -> " + v));
        // int=0, float=NaN, char=out of range

        System.out.println("--- +Infinity ---");
        convertAll(Double.POSITIVE_INFINITY).forEach((k, v) -> System.out.println(k + " -> " + v));
        // int=Integer.MAX_VALUE
    }
}

