import java.math.*;

public class Q9 {
    public static String addMoney(String a, String b) {
        BigDecimal sum = new BigDecimal(a).add(new BigDecimal(b));
        return sum.setScale(2, RoundingMode.HALF_UP).toPlainString();
    }

    public static String[] splitBill(String total, int ways) {
        BigDecimal t = new BigDecimal(total);
        BigDecimal divisor = BigDecimal.valueOf(ways);
        BigDecimal share = t.divide(divisor, 2, RoundingMode.HALF_DOWN);
        BigDecimal paidTotal = share.multiply(divisor);
        BigDecimal remainder = t.subtract(paidTotal).setScale(2, RoundingMode.HALF_UP);
        return new String[]{
            share.toPlainString(),
            remainder.toPlainString()
        };
    }

    public static void main(String[] args) {
        System.out.println("0.10 + 0.20 = " + addMoney("0.10", "0.20")); // 0.30
        System.out.println("1.23 + 4.57 = " + addMoney("1.23", "4.57")); // 5.80

        String[] split = splitBill("10.00", 3);
        System.out.println("Per person: " + split[0]); // 3.33
        System.out.println("Remainder:  " + split[1]);  // 0.01

        // vs double:
        double dSum = 0.10 + 0.20;
        System.out.println("double sum: " + dSum); // 0.30000000000000004!
    }
}

problems.description:
Handle passwords as `char[]` instead of `String` for security — `char[]` can be zeroed out after use; Strings are immutable and may linger in memory/logs.

**Example:**
char[] password = getPassword();
try { authenticate(password); }
finally { Arrays.fill(password, '\0'); } // zero out

Implement `securePasswordCheck(char[] input, char[] stored)` that zeroes both arrays after comparison.

