problems.solutionCode:
import java.util.Arrays;

public class Q10 {
    public static void storePasswordUnsafe(String password) {
        // String is immutable: after use, we can only remove our reference
        // But the String object may remain in heap/String Pool for GC to collect
        // A memory dump (heap dump) will still show the password in plaintext!
        System.out.println("Processing: " + "*".repeat(password.length()));
        password = null; // only nulls our reference — object still exists in heap
        System.out.println("String set to null, but object may still be in memory");
    }

    public static void storePasswordSafe(char[] password) {
        try {
            System.out.println("Processing password of length: " + password.length);
            // ... authenticate against stored hash ...
            System.out.println("Authentication processed");
        } finally {
            // Zero out immediately after use — no password in memory
            Arrays.fill(password, '\0');
            System.out.println("Password zeroed: " + Arrays.toString(password));
            // Memory now contains only null chars — password is gone
        }
    }

    public static void main(String[] args) {
        storePasswordUnsafe("mySecret123");
        System.out.println();
        storePasswordSafe("mySecret123".toCharArray());
        // Note: toCharArray() creates a new char[] — not the Pool object
        // After Arrays.fill, the array is zeroed
    }
}

