import java.util.regex.*;
import java.util.*;

public class Q11 {
    public static String analyzeVarUsage(String sourceCode) {
        int total = 0, goodNew = 0, methodCall = 0, literal = 0;

        Pattern varPattern = Pattern.compile("\\bvar\\s+(\\w+)\\s*=\\s*(.+?);");
        for (String line : sourceCode.split("\n")) {
            Matcher m = varPattern.matcher(line.trim());
            if (m.find()) {
                total++;
                String rhs = m.group(2).trim();
                if (rhs.startsWith("new ")) goodNew++;
                else if (rhs.matches("\\d+\.?\\d*[fFdDlL]?") || rhs.startsWith("\"")
