    public static long[] measureMemory() {
        Runtime rt = Runtime.getRuntime();
        System.gc();
        long base = rt.totalMemory() - rt.freeMemory();

        int[] primitiveArray = new int[N]; // N * 4 bytes = ~4MB
        long afterPrimitive = rt.totalMemory() - rt.freeMemory();
        long primitiveDelta = afterPrimitive - base;

        primitiveArray = null; System.gc();
        long base2 = rt.totalMemory() - rt.freeMemory();

