        Integer[] wrapperArray = new Integer[N];
        for (int i = 0; i < N; i++) wrapperArray[i] = i;
        long afterWrapper = rt.totalMemory() - rt.freeMemory();
        long wrapperDelta = afterWrapper - base2;

        wrapperArray = null;
        return new long[]{primitiveDelta, wrapperDelta};
    }

    public static void main(String[] args) {
        // Theoretical:
        System.out.println("=== Theoretical ===");
        System.out.printf("int[1M]:     %d bytes = ~%dMB%n", 1_000_000 * 4L, 4);
        System.out.printf("Integer[1M]: %d bytes = ~%dMB%n",
            1_000_000L * 4 + 1_000_000L * 16, 20); // refs + objects

