public class Q14 {
    public static void demonstratePrecisionLoss() {
        // Find the smallest positive long that cannot be represented exactly as float
        // float has 23-bit mantissa -> exact integers up to 2^24 = 16,777,216
        long firstLoss = 0;
        for (long v = 1L; v > 0; v++) {
            if (v != (long)(float) v) { firstLoss = v; break; }
        }
        System.out.println("First long→float loss at: " + firstLoss);
        // Expected: 16,777,217 (= 2^24 + 1)
        System.out.println("Expected 2^24+1 = " + ((1L << 24) + 1));
        System.out.println("(float)" + firstLoss + " = " + (float)firstLoss);
        System.out.println("Error: " + (firstLoss - (long)(float)firstLoss));
    }

    public static void main(String[] args) {
        demonstratePrecisionLoss();

        System.out.println();
        long big = 123_456_789_012_345L;
        System.out.println("Original long: " + big);
        System.out.println("As float:      " + (float) big);
        System.out.println("Difference:    " + (big - (long)(float)big));

        // IMPORTANT: long→float is WIDENING (no cast required) but loses precision!
        float f = big; // No cast needed — but precision is lost silently
        System.out.println("\nWARNING: long→float is widening (no cast) but silent precision loss!");
    }
}

