import java.util.Objects;

public class Q15 {
    static final class SafeInt implements Comparable<SafeInt> {
        private final int value;

        public SafeInt(int value) { this.value = value; }

        public SafeInt add(SafeInt other) {
            return new SafeInt(Math.addExact(this.value, other.value));
        }
        public SafeInt subtract(SafeInt other) {
            return new SafeInt(Math.subtractExact(this.value, other.value));
        }
        public SafeInt multiply(SafeInt other) {
            return new SafeInt(Math.multiplyExact(this.value, other.value));
        }

        public int intValue() { return value; }

        @Override public int compareTo(SafeInt other) {
            return Integer.compare(this.value, other.value);
        }
        @Override public boolean equals(Object o) {
            if (this == o) return true;
            if (!(o instanceof SafeInt s)) return false;
            return this.value == s.value;
        }
        @Override public int hashCode() { return Integer.hashCode(value); }
        @Override public String toString() { return String.valueOf(value); }
    }

    public static void main(String[] args) {
        SafeInt a = new SafeInt(1000);
        SafeInt b = new SafeInt(2000);
        System.out.println(a.add(b));       // 3000
        System.out.println(a.multiply(b));  // 2000000
        System.out.println(a.compareTo(b)); // negative (1000 < 2000)
        System.out.println(a.equals(new SafeInt(1000))); // true
        try {
            new SafeInt(Integer.MAX_VALUE).add(new SafeInt(1));
        } catch (ArithmeticException e) { System.out.println("Overflow caught!"); }
        try {
            new SafeInt(Integer.MIN_VALUE).subtract(new SafeInt(1));
        } catch (ArithmeticException e) { System.out.println("Underflow caught!"); }
    }
}

