import java.math.BigDecimal;
import java.util.List;

public class Q16 {
    static class NumberAccumulator<T extends Number> {
        public double sum(List<T> numbers) {
            double total = 0.0;
            for (T n : numbers) total += n.doubleValue();
            return total;
        }

        public BigDecimal preciseSum(List<T> numbers) {
            BigDecimal total = BigDecimal.ZERO;
            for (T n : numbers) {
                // Use BigDecimal arithmetic for precision
                BigDecimal bd = (n instanceof BigDecimal bd2)
                    ? bd2
                    : new BigDecimal(n.toString()); // avoid new BigDecimal(double)
                total = total.add(bd);
            }
            return total;
        }
    }

    public static void main(String[] args) {
        NumberAccumulator<Integer> intAcc = new NumberAccumulator<>();
        System.out.println(intAcc.sum(List.of(1, 2, 3, 4, 5))); // 15.0

        NumberAccumulator<Double> dblAcc = new NumberAccumulator<>();
        System.out.println(dblAcc.sum(List.of(1.1, 2.2, 3.3))); // 6.6000000000000005

        NumberAccumulator<BigDecimal> bdAcc = new NumberAccumulator<>();
        System.out.println(bdAcc.preciseSum(List.of(
            new BigDecimal("0.1"), new BigDecimal("0.2")))); // 0.3 exactly!
    }
}

