import java.util.*;
import java.util.regex.*;

public class Q18 {
    record ShadowReport(String fieldName, String context) {}

    public static List<ShadowReport> findShadowing(String sourceCode) {
        List<ShadowReport> reports = new ArrayList<>();

        // Step 1: Find instance fields (private/protected/public <type> <name>;)
        Set<String> fields = new HashSet<>();
        Pattern fieldPat = Pattern.compile(
            "(?:private|protected|public)\\s+(?:static\\s+)?(?:final\\s+)?\\w+\\s+(\\w+)\\s*;");
        Matcher fm = fieldPat.matcher(sourceCode);
        while (fm.find()) fields.add(fm.group(1));

        // Step 2: Find method/constructor parameters
        Pattern methodPat = Pattern.compile("\\w+\\s*\\(([^)]*)\\)");
        String[] lines = sourceCode.split("\n");
        for (String line : lines) {
            Matcher mm = methodPat.matcher(line.trim());
            if (!mm.find()) continue;
            String params = mm.group(1);
            if (params.isBlank()) continue;
            // Extract param names from 'Type name, Type name2' etc
            for (String param : params.split(",")) {
                String[] parts = param.trim().split("\\s+");
                if (parts.length >= 2) {
                    String paramName = parts[parts.length - 1].replaceAll("[^a-zA-Z0-9_]", "");
                    if (fields.contains(paramName))
                        reports.add(new ShadowReport(paramName, line.trim()));
                }
            }
        }
        return reports;
    }

    public static void main(String[] args) {
        String code = "class Person {\n  private String name;\n  private int age;\n" +
            "  Person(String name, int age) { this.name = name; this.age = age; }\n" +
            "  void setName(String name) { this.name = name; }\n}";
        List<ShadowReport> shadows = findShadowing(code);
        System.out.println("Found " + shadows.size() + " shadowing(s):");
        shadows.forEach(r -> System.out.println("  '" + r.fieldName() + "' in: " + r.context()));
    }
}

