import java.util.*;

public class Q19 {
    public static void typeHierarchy(Object obj) {
        System.out.println("Type hierarchy for: " + obj.getClass().getName());
        printHierarchy(obj.getClass(), 0, new HashSet<>());
    }

    static void printHierarchy(Class<?> clazz, int indent, Set<Class<?>> visited) {
        if (clazz == null || visited.contains(clazz)) return;
        visited.add(clazz);
        String pad = "  ".repeat(indent);
        System.out.println(pad + (indent > 0 ? "↑ " : "") + clazz.getSimpleName() +
            (clazz.isInterface() ? " [interface]" : ""));

        // Print interfaces (sorted for consistency)
        Class<?>[] ifaces = clazz.getInterfaces();
        Arrays.sort(ifaces, Comparator.comparing(Class::getSimpleName));
        for (Class<?> iface : ifaces)
            printHierarchy(iface, indent + 1, visited);

        // Print superclass
        printHierarchy(clazz.getSuperclass(), indent + 1, visited);
    }

    public static void main(String[] args) {
        typeHierarchy(new java.util.ArrayList<>());
        System.out.println();
        typeHierarchy(Integer.valueOf(42));
    }
}

