    public static List<Question> getQuestions() {
        return List.of(
            new Question("Q1",
                "byte b = 127; System.out.println((byte)(b+1));",
                "-128",
                "byte overflow wraps: 127+1=128 as int, cast to byte gives -128"),
            new Question("Q2",
                "Integer a=127, b=127; System.out.println(a==b);",
                "true",
                "Integer cache: -128 to 127. 127 is cached, a==b is same object"),
            new Question("Q3",
                "Integer c=128, d=128; System.out.println(c==d);",
                "false",
                "128 not cached. Different objects. Use .equals() for Integer comparison"),
            new Question("Q4",
                "System.out.println(0.1+0.2==0.3);",
                "false",
                "IEEE 754 floating point: 0.1+0.2=0.30000000000000004, not exactly 0.3"),
            new Question("Q5",
                "System.out.println((int)3.99);",
                "3",
                "Narrowing cast truncates (does not round). 3.99 -> 3"),
            new Question("Q6",
                "String a=\"hi\", b=\"hi\"; System.out.println(a==b);",
                "true",
                "String literals interned in pool. Same literal = same object"),
            new Question("Q7",
                "String a=\"hi\", b=new String(\"hi\"); System.out.println(a==b);",
                "false",
                "new String() creates new heap object, bypasses pool"),
            new Question("Q8",
                "System.out.println(Integer.MAX_VALUE+1);",
                "-2147483648",
                "int overflow wraps to MIN_VALUE. Silent in Java"),
            new Question("Q9",
                "long x=16777217L; float f=x; System.out.println(f==(float)x && x!=(long)f);",
                "true",
                "16777217 = 2^24+1. First long value that can't be exactly represented as float"),
            new Question("Q10",
                "var x=42; x=\"hello\"; System.out.println(x);",
                "COMPILE ERROR",
                "var infers int from 42. Cannot assign String to int variable")
        );
    }

    public static boolean checkAnswer(Question q, String userAnswer) {
        return q.expectedOutput().trim().equalsIgnoreCase(userAnswer.trim());
    }

    public static void main(String[] args) {
        int correct = 0;
        List<Question> qs = getQuestions();
        for (Question q : qs) {
            boolean ok = checkAnswer(q, q.expectedOutput());
            System.out.printf("%s [%s]: %s%n", q.id(), ok ? "PASS" : "FAIL", q.code());
